head.script:
scwin.initData = {
	"isValidate" : false,
	"isSaveProcess" : false,
	"acbMappingDivCdObj" : {
		"ecsElcpwstnDivNm" : "cmmnCd"
	},
	"acbMappingIemCdObj" : {
		"iemNm" : "cmmnCd"
	},
	"acbMappingNmObj" : {
	},
	"valInfo" : [
		{id : "ecsElcpwstnDivNm", mandatory : true},
		{id : "cnvrEqpLcNm", minLength : 1, maxByteLength : 80, mandatory : true},
		{id : "cnvrEqpNm", minLength : 1, maxByteLength : 40, mandatory : true},
		{id : "iemNm", mandatory : true},
		{id : "mnfctYear", maxByteLength : 4, number : true, dateFunc : ecsLib.validatorYear},
		{id : "eqpQtyVu", maxByteLength : 20, number : true},
		{id : "erorExamHistYm", maxByteLength : 6, number : true, dateFunc : ecsLib.validatorYearMonth},
		{id : "erorExamPlanYm", maxByteLength : 6, number : true, dateFunc : ecsLib.validatorYearMonth},
		{id : "erorExamAcmsltYm", maxByteLength : 6, number : true, dateFunc : ecsLib.validatorYearMonth},
		{id : "rmCtnt", maxByteLength : 80},
		{id : "rowStatus", maxByteLength : 40},
	]
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSME3300000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 초기 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("ecsElcpwstnDivCd", "ALL");
	dmaSearchParam.set("iemCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var ecsElcpwstnDivCd = dmaSearchParam.get("ecsElcpwstnDivCd");
	var iemCd = dmaSearchParam.get("iemCd");

	var queryString = `?ecsElcpwstnDivCd=${ecsElcpwstnDivCd}`;
	queryString += `&iemCd=${iemCd}`;

	var option = {
		action : "me/cnvreqp/retrieve-cnvr-eqp.do"
			+ queryString,
		method : "get",
		resData : dltCnvrEqpList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};

	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	spnTotalRow.setValue(dltCnvrEqpList.getRowCount());
	var mandatoryList = scwin.initData.valInfo.filter(obj => obj.mandatory);

	for (var i = 0; i < dltCnvrEqpList.getRowCount(); i++) {
		mandatoryList.forEach(obj => {
			grdCnvrEqpList.setCellReadOnly(i, obj.id, true);
		});
	}
	var nowYm = $p.getCurrentServerDate("yyyy");
	dltCnvrEqpList.getAllJSON().forEach((obj, i) => {
		// 오차시험/국가검정 계획 년월 올해면 셀 폰트,배경 색 변경 _240215
		if (obj.erorExamPlanYm != "" && obj.erorExamPlanYm.startsWith(nowYm)) {
			grdCnvrEqpList.setCellBackgroundColor(i, "erorExamPlanYm", "#F5F5FF");
			grdCnvrEqpList.setCellColor(i, "erorExamPlanYm", "#0000FF");
		} else {
			//grdCnvrEqpList.setCellBackgroundColor(i, "erorExamPlanYm", "");
			//grdCnvrEqpList.setCellColor(i, "erorExamPlanYm", "");
		}
	});
	scwin.initData.isValidate = false;
};

/**
 * 그리드뷰 행을 추가한다.
 * @param
 * @return
 */
scwin.btnAddRow_onclick = function() {
	var newIndex = dltCnvrEqpList.insertRow();

	grdCnvrEqpList.setFocusedCell(newIndex, "deptNm", true);
};

/**
 * 그리드뷰 행을 삭제한다.
 * @param
 * @return
 */
scwin.btnDelRow_onclick = function() {
	var rowIndexList = grdCnvrEqpList.getAllFocusedRowIndex();

	dltCnvrEqpList.removeRows(rowIndexList);
};

/**
 * 그리드뷰의 내용을 검증한다.
 * @param
 * @return
 */
scwin.btnValidate_onclick = function(confirmValue) {
	if (confirmValue == true || confirmValue == undefined) {
		if (dltCnvrEqpList.getModifiedData() == "") {
			// 처리할 데이터가 없습니다.
			comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
			return;
		}

		dltCnvrEqpList.getAllJSON().forEach((obj, idx) => {
			if (obj.rowStatus == "U") {
				var isCd = dltAutoCondition1.getAllJSON().find(cdObj => cdObj.cmmnCd == obj.deptNm);
				if (isCd) {
					dltCnvrEqpList.setCellData(idx, "ecsElcpwstnDivCd", obj.deptNm, true);
				}
			}
		});
		if (utilLib.validateGridView(grdCnvrEqpList, scwin.initData.valInfo)) {
			var columnList = scwin.initData.valInfo.filter(obj => obj.mandatory).flatMap(obj => obj.id.replace("ecsElcpwstnDivCd", "ecsElcpwstnDivCd"));
			if (ecsLib.gridViewPkDuplicationCheck(grdCnvrEqpList, dltCnvrEqpList, columnList)) {
				// 중복 데이터가 있습니다.
				return;
			}

			if (ecsLib.validateGridViewAcb(grdCnvrEqpList, dltAutoCondition1, scwin.initData.acbMappingDivCdObj, scwin.initData.acbMappingNmObj)) {
				// 해당하는 {발전소}이(가) 존재하지 않습니다.
				return;
			}
			if (ecsLib.validateGridViewAcb(grdCnvrEqpList, dltAutoCondition2, scwin.initData.acbMappingIemCdObj, scwin.initData.acbMappingNmObj)) {
				// 해당하는 {구분}이(가) 존재하지 않습니다.
				return;
			}
			scwin.initData.isValidate = true;
			if (scwin.initData.isSaveProcess) {
				scwin.initData.isSaveProcess = false;
				scwin.btnSave_onclick();
			} else {
				// 데이터 검증이 완료되었습니다.
				comLib.alert($p, utilLib.getMessage("ECS.INFO.00102"));
			}
		}
	} else {
		scwin.initData.isSaveProcess = false;
	}
};

/**
 * 그리드뷰의 내용을 수정/저장한다.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	scwin.initData.isSaveProcess = false;
	if (dltCnvrEqpList.getModifiedData() == "") {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}

	if (scwin.initData.isValidate) {
		var addCount = 0;
		var modifyCount = 0;
		var delCount = 0;
		dltCnvrEqpList.getModifiedJSON().forEach(obj => {
			var rowStatus = obj.rowStatus;
			switch(rowStatus) {
				case "C":
					// 추가
					addCount++;
					break;
				case "U":
					// 수정
					modifyCount++;
					break;
				case "E":
					// 삭제
					delCount++;
					break;
				default:
					break;
			}
		});
		var extendMsg = ecsLib.extendCustomSaveMsg(addCount, modifyCount, delCount);
		// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
		ecsLib.saveRsn($p, `${dltCnvrEqpList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0] + extendMsg, "scwin.saveConfirmCallback");
	} else {
		scwin.initData.isSaveProcess = true;
		// 데이터 검증 후 저장 가능합니다.\n검증하시겠습니까?
		comLib.confirm($p, utilLib.getMessage("ECS.INFO.00101"), "scwin.btnValidate_onclick", true);
		return;
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var requestData = {};
	requestData.dltCnvrEqpList = dltCnvrEqpList.getModifiedJSON();

	var option = {
		action : "me/cnvreqp/process-cnvr-eqp.do",
		reqData : requestData,
		success : "scwin.saveConfirmSuccessCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> resBody
 * @return
 */
scwin.saveConfirmSuccessCallback = function(resBody) {
	comLib.alert($p, resBody.message.code_name);

	scwin.btnInqire_onclick();
};

/**
 * 작업중이던 내용을 취소한다.
 * @param
 * @return
 */
scwin.btnCancl_onclick = function() {
	scwin.btnInqire_onclick();
};

/**
 * 데이터컬렉션의 추가/변경/삭제 시 이벤트
 * @param
 * @return
 */
scwin.dltCnvrEqpList_ondatachange = function(info) {
	scwin.initData.isValidate = false;
};

scwin.acbEcsElcpwstnDivCd_onviewchange = function(info) {
	dmaSearchParam.set("ecsElcpwstnDivCd", info.newValue);
};

scwin.acbIemCd_onviewchange = function(info) {
	dmaSearchParam.set("iemCd", info.newValue);
};

scwin.grdCnvrEqpList_onafteredit = function(row, col, value) {
	ecsLib.updateGridViewFontColor(grdCnvrEqpList, row, col);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnSubTitle.getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 10,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	// 데이터가 없어도 탬플릿만 다운받을 수 있게 comLib.downloadExcel 말고 grdID.advancedExcelDownload 적용_231113
	var options = {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		startRowIndex : 1,
		startColumnIndex : 0,
		rowHeight : 40,
		useStyle: true,
		useDataFormat: true,
		applyDataFormat : true,
		hidden: 1
	};
	/*
	// 엑셀 업로드 샘플데이터_231206
	if (!grdCnvrEqpList.getAllJSON().length) {
		var dataList = $p.getComponentById(grdCnvrEqpList.getDataList());
		//dataList.insertJSON();
	}
	 */
	grdCnvrEqpList.advancedExcelDownload(options, infoArr);
};

/**
 * 엑셀의 내용을 그리드에 업로드 한다.
 * @return
 */
 scwin.btnUploadExcel_onclick = function() {
	var options = {
		type : 1,
		headerExist : 1,
		startRowIndex : 1,
		startColumnIndex : 0,
		endColumnIndex : 10,
		sheetNo : 0,
		append : 0,
		status: "C",
		useMaxByteLength : true
	};
	comLib.uploadExcel(grdCnvrEqpList, options);
};

/**
 * 엑셀 내용을 그리드에 저장한다.
 * @return
 */
scwin.grdCnvrEqpList_onfilereadend = function(value) {
	var dltData = dltCnvrEqpList.getAllJSON();
	var dltAuto1 = dltAutoCondition1.getAllJSON();
	var dltAuto3 = dltAutoCondition3.getAllJSON();
	// set JSON
	for (var idx = 0; idx < dltData.length; idx++) {
		var ecsElcpwstnDivNm = (dltAuto1.find(obj => obj.cmmnCd == dltData[idx].ecsElcpwstnDivNm) || 0).cmmnCd;
		dltCnvrEqpList.setCellData(idx, "ecsElcpwstnDivNm", ecsElcpwstnDivNm);
		var iemNm = (dltAuto3.find(obj => obj.cmmnCdNm == dltData[idx].iemNm) || 0).cmmnCd;
		dltCnvrEqpList.setCellData(idx, "iemNm", iemNm);
	}
};
